import React, { useEffect, useRef } from 'react'
import styled from 'styled-components'
import ArrowBackIosIcon from '@material-ui/icons/ArrowBackIos';

export default function ToTop() {
    const toTop = useRef()
    
    useEffect(() => {
        function handleScroll() {
            if (window.scrollY > window.innerHeight / 2) {
                toTop.current.style.opacity = 1
                toTop.current.style.pointerEvents = "all"
            } else {
                toTop.current.style.opacity = 0
                toTop.current.style.pointerEvents = "none"
            }
        }

        window.addEventListener('scroll', handleScroll)
    
        return () => window.removeEventListener('scroll', handleScroll)

    }, [])


    return (
        <Container onClick={() => window.scrollTo(0, 0)} ref={toTop}>
            <ArrowBackIosIcon/>
        </Container>
    )
}


const Container = styled.div`
    position: fixed;
    z-index: 69;
    right: 0;
    top: 50vh;
    transform: translateY(-50%);
    height: 5vh;
    width: 5vh;
    background-color: #00000055;
    cursor: pointer;
    display: grid;
    place-content: center;
    mix-blend-mode: multiply;
    opacity: 0;
    transition: opacity .5s ease-in;
    border-radius: 5px 0 0 5px;
    >svg {
        margin-top: 20px;
        transform: rotate(90deg);
        color: white;
        opacity: 1;
        animation: totop 1s forwards infinite;
        pointer-events: none;
        @keyframes totop {
            to {
                transform: rotate(90deg) translateX(-15px);
                opacity: 0;
            }
        }
    }
    @media screen and (max-width: 600px) {
        top: 100vh;
        transform: translateY(-100%);
    }
`