import React from 'react'
import styled from 'styled-components'
import Loading from '../../components/Loading'
import facebook from '../../images/logos/facebook.jpg'
import twitter from '../../images/logos/twitter.jpg'
import netflix from '../../images/logos/netflix.jpg'
import paypal from '../../images/logos/paypal.jpg'
import github from '../../images/logos/github.jpg'
import stripe from '../../images/logos/stripe.jpg'
import header from '../../images/header.jpg'
import clipart1 from '../../images/clipart1.png'
import InfoOutlinedIcon from '@material-ui/icons/InfoOutlined';
import CheckCircleIcon from '@material-ui/icons/CheckCircle';
import illustration from '../../images/illustration-buy.png'
import BuySection from './BuySection'
import { motion  } from 'framer-motion'


export default function Shoppage({lang}) {
    const wrapper = {
        show: {
            transition: {
                staggerChildren: 0.1,
                staggerDirection: 1,
                delayChildren: 1.3,
            }
        }
    }
    
    const elem = {
        hide: { opacity: 0, x: 100 },
        show: { opacity: 1, x: 0 }
    }
    
    return (
        <>
            <Loading/>

            <Container>
                <Header></Header>
                {lang === "ro" ? 
                <Wrapper>
                    <Title >
                        <Image as={motion.img} 
                            initial={{opacity: 0, y: 100}} 
                            animate={{opacity: 1, y: 0}} 
                            transition={{delay: 1.3, duration: 1}}
                            src={illustration} alt="illustration" />
                        <motion.span initial={{opacity: 0, x: -100}} 
                            animate={{opacity: 1, x: 0}} 
                            transition={{delay: 1.3, duration: 1}}><InfoOutlinedIcon />De știut...</motion.span>
                    </Title>
                    <Ul as={motion.ul} variants={wrapper} initial="hide" animate="show">
                        <ClipArt src={clipart1} alt="clip art image" />
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            Toate proiectele folosesc limbajul de programare ReactJS, o bibliotecă JavaScript întreținută de Facebook și folosită de site-uri ca bineînțeles <a href="https://www.facebook.com/" target="_blank" rel="noreferrer">Facebook <Img src={facebook} alt="facebook logo"/></a>, <a href="https://twitter.com/home" target="_blank" rel="noreferrer">Twitter <Img src={twitter} alt="twitter logo"/></a>, <a href="https://www.netflix.com/ro-en/" target="_blank" rel="noreferrer">Netflix <Img src={netflix} alt="netflix logo"/></a>, <a href="https://www.paypal.com/ro/home" target="_blank" rel="noreferrer">PayPal <Img src={paypal} alt="paypal logo"/></a> și mulți alții.
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/>
                            Optimizare SEO (Search Engine Optimization) - Optimizare pentru vizibilitatea și descoperirea  site-ului pe motoarele de căutare precum Google, Bing, Yahoo, etc. atât cât și optimizarea acestuia atunci când este distribuit pe rețelele de socializare ca Facebook și Twitter.
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            Hosting (Găzduire web - uploadare fișiere) - este gratuită pe contul meu de <a href="https://github.com/codmitu" target="_blank" rel="noreferrer">Github <Img src={github} alt="github logo"/></a>, dar se poate găzdui și pe alte site-uri contra cost la cerere.
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            Domeniul (ex: www.domeniu.ro) - contra cost, prețurile variază in funcție de domeniu: .ro (40 RON), .com (50 RON), .info (80 RON), etc. Acestea se înregistrează pe <a href="https://www.datahost.ro/" target="_blank" rel="noreferrer">datahost.ro</a>, sau domeniu gratuit pe contul meu de <a href="https://github.com/codmitu" target="_blank" rel="noreferrer">Github <Img src={github} alt="github logo"/></a> (ex: www.codmitu.github.io/siteul-tau).
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            Business Email - Email personalizat (Gmail), 26 RON/lună, acesta se înregistrează pe <a href="https://www.datahost.ro/" target="_blank" rel="noreferrer">datahost.ro</a>.
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            Mentenanță și modificare text/imagini gratuit o dată pe lună timp de 1 an.
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            Adăugare alte pagini, widgeturi, caracteristici după publicarea websitului - contra cost de la 5 RON în funcție de complexitate.
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            Integrare platformă procesare plată cu cardul. La cerere, contra cost 500 RON - aplicație de procesare plăți bancare <a href="https://stripe.com/en-gb-ro" target="_blank" rel="noreferrer">Stripe <Img src={stripe} alt="stripe logo" /></a>
                        </Li>
                    </Ul>
                </Wrapper> :
                <Wrapper>
                    <Title >
                        <Image as={motion.img} 
                            initial={{opacity: 0, y: 100}} 
                            animate={{opacity: 1, y: 0}} 
                            transition={{delay: 1.3, duration: 1}}
                            src={illustration} alt="illustration" />
                        <motion.span initial={{opacity: 0, x: -100}} 
                            animate={{opacity: 1, x: 0}} 
                            transition={{delay: 1.3, duration: 1}}><InfoOutlinedIcon />To know...</motion.span>
                    </Title>
                    <Ul as={motion.ul} variants={wrapper} initial="hide" animate="show">
                        <ClipArt src={clipart1} alt="clip art image" />
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            All projects use ReactJS programming language, a JavaScript library owned and maintained by Facebook and used by <a href="https://www.facebook.com/" target="_blank" rel="noreferrer">Facebook <Img src={facebook} alt="facebook logo"/></a>, <a href="https://twitter.com/home" target="_blank" rel="noreferrer">Twitter <Img src={twitter} alt="twitter logo"/></a>, <a href="https://www.netflix.com/ro-en/" target="_blank" rel="noreferrer">Netflix <Img src={netflix} alt="netflix logo"/></a>, <a href="https://www.paypal.com/ro/home" target="_blank" rel="noreferrer">PayPal <Img src={paypal} alt="paypal logo"/></a> and many more.
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/>
                            Search Engine Optimization - Search optimization for visibility and descovery of the website on the search engines like Google, Bing, Yahoo, etc. also when the website is beeig shared on social platforms like Facebook and Twitter.
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            Hosting (hosted files) - it's free on my github account <a href="https://github.com/codmitu" target="_blank" rel="noreferrer">Github <Img src={github} alt="github logo"/></a>, but it can be hosted on other platforms aswell.
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            Domain (eg: www.domeniu.com) - custom domain name have different prices depending on domain: .ro (&euro; 7.49), .com (&euro; 9.90), .info (&euro; 14.99), etc. These are purchased from <a href="https://www.datahost.ro/" target="_blank" rel="noreferrer">datahost.ro</a>, or free domain on my <a href="https://github.com/codmitu" target="_blank" rel="noreferrer">Github <Img src={github} alt="github logo"/></a> account (eg: www.codmitu.github.io/your-website).
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            Business Email - (Gmail), &euro; 5.20/month, purchased from <a href="https://www.datahost.ro/" target="_blank" rel="noreferrer">datahost.ro</a>.
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            Maintenance and modify text/images for free once a month for a year.
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            Adding extra images, widgets, characteristics after the website has been published will charge extra fees depending on the complexity (from &euro; 1).
                        </Li>
                        <Hr/>
                        <Li as={motion.li} variants={elem}><CheckCircleIcon/> 
                            Integration of card payments powered by <a href="https://stripe.com/en-gb-ro" target="_blank" rel="noreferrer">Stripe <Img src={stripe} alt="stripe logo" /></a>. On request this feature adds extra &euro; 100 to total charge.
                        </Li>
                    </Ul>
                 </Wrapper>
                }
                <BuySection lang={lang}/>
            </Container>
        </>
    )
}


const Container = styled.article`
    position: relative;
    min-height: 100vh;
    overflow-x: hidden;
`
const Header = styled.header`
    background: url(${header}) no-repeat bottom center / cover;
    height: 300px;
    width: 100%;
    opacity: 0.3;
    position: absolute;
`
const Wrapper = styled.section`
    display: flex;
    justify-content: space-around;
    max-width: 1500px;
    margin: 0 auto;
    padding: 100px 0 0;
    position: relative;
    @media screen and (max-width: 900px) {
        flex-direction: column;
        gap: 30px;
    }
`
const Title = styled.div`
    font-size: var(--bf);
    font-weight: 500;
    font-family: var(--fsc);
    display: flex;
    align-items: flex-start;
    justify-content: center;
    flex: 0.5;
    color: #444444;
    position: relative;
    >span {
        position: relative;
        display: flex;
        align-items: center;
        &::after {
            position: absolute;
            content: '';
            bottom: -20px;
            right: 50px;
            width: 100px;
            height: 2px;
            background-color: var(--cbd);
        }
        >svg {
            font-size: var(--bf);
            color: var(--cbd);
        }
    }
`
const Image = styled.img`
    width: 700px;
    position: absolute;
    top: 300px;
    left: -5vw;
    z-index: -1;
    -webkit-box-reflect:  below -60px linear-gradient(to bottom, rgba(255, 255, 255, 0) 10%, rgba(255, 255, 255, 0.1) 100%);
    @media screen and (max-width: 900px) {
        display: none;
    }
`
const Ul = styled.ul`
    flex: 0.5;
    background-color: #fafafad2;
    padding: 2vw 5vw;
    border-radius: 5px;
    position: relative;
`
const ClipArt = styled.img`
    position: absolute;
    top: -50px;
    left: -50px;
    width: calc(1rem + 10vw);
    @media screen and (max-width: 900px) {
        top: -20px;
        left: -20px;
    }
`
const Li = styled.li`
    margin: 15px 0;
    line-height: 2;
    font-size: var(--sf);
    list-style: none;
    >svg {
        color: var(--cgd);
        font-size: var(--sf);
        margin-bottom: -3px;
    }
    >a {
        color: var(--cbd);
        text-decoration: none;
        &:hover {
            color: var(--cbl);
        }
    }
`
const Hr = styled.hr`
    background-color: lightgray;
    border: none;
    height: 1px;
    width: 69%;
    margin: 20px auto;
`
const Img = styled.img`
    max-height: 1rem;
    vertical-align: middle;
    border-radius: 3px;
`
