import React from 'react'
import frizerie from '../../images/frizerie-devices.png'
import portfolio from '../../images/portfolio-devices.png'
import cutite from '../../images/cutite-devices.png'
import styled from 'styled-components'
import LinkIcon from '@material-ui/icons/Link';
import ChevronRightSharpIcon from '@material-ui/icons/ChevronRightSharp';
import bg from "../../images/bg.svg"
import { motion, useAnimation  } from 'framer-motion'
import { useInView } from 'react-intersection-observer';
import { useMotion } from '../../components/useMotion'

export default function AboutSection({cursor, lang}) {
    const handleEnter = () => {
        cursor.current.classList.remove('outLink2')
        cursor.current.classList.add('onLink2')
    }
    const handleLeave = () => {
        cursor.current.classList.add('outLink2')
        cursor.current.classList.remove('onLink2')
        setTimeout(() => {
            cursor.current.classList.remove('outLink2')
        }, 1000);
    }

    // website presentation animation
    const controls1 = useAnimation();
    const { ref: ref1, inView: inView1 } = useInView({
        "triggerOnce": true
    });
    const {
        imageVariants: imageVariant1, 
        listVariants: listVariant1
    } = useMotion({inview: inView1, controls: controls1})

    // contact page presentation animation
    const controls2 = useAnimation();
    const { ref: ref2, inView: inView2 } = useInView({
        "triggerOnce": true
    });
    const {
        imageVariants: imageVariant2,
        listVariants: listVariant2
    } = useMotion({inview: inView2, controls: controls2})
    
    // webshop presentation animation
    const controls3 = useAnimation();
    const { ref: ref3, inView: inView3 } = useInView({
        "triggerOnce": true
    });
    const {
        imageVariants: imageVariant3,
        listVariants: listVariant3
    } = useMotion({inview: inView3, controls: controls3})

    return (
        <Container >
            <Wrapper>
                <Img src={frizerie} 
                    alt="project" 
                    as={motion.img}
                    ref={ref1}
                    variants={imageVariant1}
                    animate={controls1}
                />
                <Text ><MyLink  onMouseEnter={handleEnter} onMouseLeave={handleLeave} href="https://codmitu.github.io/frizerie-website/" target="_blank"><LinkIcon/>Website</MyLink>
                    {lang === "ro" ?
                        <Ul>
                            <Li custom={0} variants={listVariant1} animate={controls1}>
                                <ChevronRightSharpIcon/> Website de prezentare</Li>
                            <Li custom={1} variants={listVariant1} animate={controls1}>
                                <ChevronRightSharpIcon/> Pagini unice: 1 - 6</Li>
                            <Li custom={2} variants={listVariant1} animate={controls1}>
                                <ChevronRightSharpIcon/> Design responsive</Li>
                            <Li custom={3} variants={listVariant1} animate={controls1}>
                                <ChevronRightSharpIcon/> Formular de contact pe email</Li>
                            <Li custom={4} variants={listVariant1} animate={controls1}>
                                <ChevronRightSharpIcon/> Hosting Gratuit</Li>
                            <Li custom={5} variants={listVariant1} animate={controls1}>
                                <ChevronRightSharpIcon/> Optimizare SEO</Li>
                        </Ul> :
                        <Ul>
                            <Li custom={0} variants={listVariant1} animate={controls1}>
                                <ChevronRightSharpIcon/> Presentation website</Li>
                            <Li custom={1} variants={listVariant1} animate={controls1}>
                                <ChevronRightSharpIcon/> Unic pages: 1 - 6</Li>
                            <Li custom={2} variants={listVariant1} animate={controls1}>
                                <ChevronRightSharpIcon/> Responsive Design</Li>
                            <Li custom={3} variants={listVariant1} animate={controls1}>
                                <ChevronRightSharpIcon/> Email contact form</Li>
                            <Li custom={4} variants={listVariant1} animate={controls1}>
                                <ChevronRightSharpIcon/> Free hosting</Li>
                            <Li custom={5} variants={listVariant1} animate={controls1}>
                                <ChevronRightSharpIcon/> SEO</Li>
                        </Ul>
                    }
                </Text>
            </Wrapper>
            <Wrapper>
                <Text><MyLink onMouseEnter={handleEnter} onMouseLeave={handleLeave} href="https://codmitu.github.io/portfolio-demo/" target="_blank"><LinkIcon/>Contact Page</MyLink>
                    {lang === "ro" ?
                        <Ul>
                            <Li custom={0} variants={listVariant2} animate={controls2}>
                                <ChevronRightSharpIcon/> Pagină de destinație</Li>
                            <Li custom={1} variants={listVariant2} animate={controls2}>
                                <ChevronRightSharpIcon/> Pagini unice: 1</Li>
                            <Li custom={2} variants={listVariant2} animate={controls2}>
                                <ChevronRightSharpIcon/> Design responsive</Li>
                            <Li custom={3} variants={listVariant2} animate={controls2}>
                                <ChevronRightSharpIcon/> Formular de contact pe email</Li>
                            <Li custom={4} variants={listVariant2} animate={controls2}>
                                <ChevronRightSharpIcon/> Hosting Gratuit</Li>
                            <Li custom={5} variants={listVariant2} animate={controls2}>
                                <ChevronRightSharpIcon/> Optimizare SEO</Li>
                        </Ul> :
                        <Ul>
                            <Li custom={0} variants={listVariant2} animate={controls2}>
                                <ChevronRightSharpIcon/> Landing Page</Li>
                            <Li custom={1} variants={listVariant2} animate={controls2}>
                                <ChevronRightSharpIcon/> Unic pages: 1</Li>
                            <Li custom={2} variants={listVariant2} animate={controls2}>
                                <ChevronRightSharpIcon/> Responsive Design</Li>
                            <Li custom={3} variants={listVariant2} animate={controls2}>
                                <ChevronRightSharpIcon/> Email contact form</Li>
                            <Li custom={4} variants={listVariant2} animate={controls2}>
                                <ChevronRightSharpIcon/> Free hosting</Li>
                            <Li custom={5} variants={listVariant2} animate={controls2}>
                                <ChevronRightSharpIcon/> SEO</Li>
                        </Ul>
                    }
                </Text>
                <Img  src={portfolio} 
                    alt="project"
                    as={motion.img}
                    ref={ref2}
                    variants={imageVariant2}
                    animate={controls2}
                />
            </Wrapper>
            <Wrapper>
                <Img  src={cutite} 
                    alt="project"
                    as={motion.img}
                    ref={ref3}
                    variants={imageVariant3}
                    animate={controls3}
                    />
                <Text ><MyLink onMouseEnter={handleEnter} onMouseLeave={handleLeave} href="https://codmitu.github.io/stripe-test/" target="_blank"><LinkIcon/>Webshop</MyLink>
                    {lang === "ro" ?
                        <Ul>
                            <Li custom={0} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Magazin online sau Blog</Li>
                            <Li custom={1} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Pagini unice: 1 - 12</Li>
                            <Li custom={2} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Design responsive</Li>
                            <Li custom={3} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Formular de contact pe email</Li>
                            <Li custom={4} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Review-uri clienți</Li>
                            <Li custom={5} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Autentificare client/admin</Li>
                            <Li custom={6} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Adăugare/ștergere produse</Li>
                            <Li custom={7} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Încărcare imagini produse</Li>
                            <Li custom={8} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Produse unice: 50</Li>
                            <Li custom={9} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Hosting gratuit</Li>
                            <Li custom={10} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Optimizare SEO</Li>
                            <Li custom={11} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Plata cu cardul</Li>
                        </Ul> :
                        <Ul>
                            <Li custom={0} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Online shop or Blog</Li>
                            <Li custom={1} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Unic pages: 1 - 12</Li>
                            <Li custom={2} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Responsive Design</Li>
                            <Li custom={3} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Email contact form</Li>
                            <Li custom={4} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Clients Reviews</Li>
                            <Li custom={5} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Client/Admin Authentication</Li>
                            <Li custom={6} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Add/Delete products</Li>
                            <Li custom={7} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Upload products images</Li>
                            <Li custom={8} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Unic products: 50</Li>
                            <Li custom={9} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Free hosting</Li>
                            <Li custom={10} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> SEO</Li>
                            <Li custom={11} variants={listVariant3} animate={controls3}>
                                <ChevronRightSharpIcon/> Card payment</Li>
                        </Ul>
                    }
                </Text>
            </Wrapper>
        </Container>
    )
}



const Container = styled.section`
    display: flex;
    justify-content: space-around;
    flex-direction: column;
    pointer-events: none;
    min-height: 200vh;
    background: url(${bg}) no-repeat center center/ cover;
    @media screen and (max-width: 1030px) {
        background-size: auto 120%;
    }
`
const Wrapper = styled.div`
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 10vw;
    margin: 10vh 5vw;
    @media screen and (max-width: 1030px) {
        flex-direction: column;
        justify-content: space-evenly;
        &:nth-child(2) {
            flex-direction: column-reverse;
        }
    }
` 
const Img = styled.img`
    max-width: 50%;
    max-height: 50vh;
    text-align: center;
    height: fit-content;
    filter: drop-shadow(10px 10px 10px rgba(0,0,0,0.5));
    @media screen and (max-width: 1030px) {
        max-width: 90%;
        max-height: 50vh;
    }
`
const Text = styled.div`
    font-family: var(--fsss);
`
const MyLink = styled.a`
    pointer-events: all;
    font-size: var(--mf);
    cursor: pointer;
    text-decoration: none;
    color: var(--crd);
    position: relative;
    z-index: 1;
    >svg {
        color: var(--cbl);
    }
    &:hover {
        text-decoration: underline;
    }
    &:visited {
        >svg {
            color: var(--crl);
        }
    }
`
const Ul = styled.ul`
    font-size: var(--sf);
    margin-left: 50px;
    
`
const Li = styled(motion.li)`
    list-style: none;
    display: flex;
    align-items: center;
    margin-top: 10px;
    color: #1a1a1a;
    >svg {
        color: var(--cgd);
    }
`