import React, { useEffect, useState } from 'react'
import styled from 'styled-components'
import ClientReviewCard from './ClientReviewCard'
import { db } from '../../components/firebase'
import FlipMove from 'react-flip-move';


export default function ClientReviewsSection({lang}) {
    const [reviews, setReviews] = useState([])

    useEffect(() => {
        db.collection('cm-reviews').where("public", "==", true).orderBy('timestamp', 'desc').limit(3).onSnapshot(snap => (
            setReviews(snap.docs.map(doc => (
                {
                    id: doc.id,
                    data: doc.data()
                }
            )))
        ))
    }, [])

    

    return (
        <Container>

            {reviews.length < 1 ? <Title>{lang === "ro" ? "Adăugați o evaluare" : "Write a review"}</Title> : <Title>{lang === "ro" ? "Ce spun clienții?" : "What the clients say?"}</Title>}
            <Wrapper>
                <FlipMove>
                    {reviews && reviews.map((review, i) => (
                        <ClientReviewCard key={i} review={review}/>

                    ))}
                </FlipMove>
            </Wrapper>
        </Container>
    )
}


const Container = styled.section`
    margin-bottom: 100px;
`
const Title = styled.h1`
    font-weight: 400;
    margin: 100px 0 100px 50px;
    font-size: 2rem;
    color: #2b2b2b;
    font-family: var(--fsss);
    position: relative;
    pointer-events: none;
    &::after {
        content: '';
        position: absolute;
        bottom: -30px;
        left: 0;
        transform: translateX(50%);
        width: 200px;
        height: 2px;
        background-color: #00000092;
    }
`
const Wrapper = styled.div`
    >div {
        display: flex;
        justify-content: space-evenly;
        align-items: flex-end;
        flex-wrap: wrap;
    }

`
