import {  NavLink, useHistory } from 'react-router-dom'
import { Avatar } from '@material-ui/core'
import React, { useRef } from 'react'
import styled from 'styled-components'
import logo from '../images/codmitu.svg'
import ro from '../images/logos/ro.png'
import uk from '../images/logos/uk.png'
import {motion, useCycle} from 'framer-motion'
import { auth } from './firebase'
import { useDispatch } from 'react-redux'
import { logout } from '../features/userSlice'
import { Hamburger } from './Hamburger'
import { useDimensions } from './useDimensions'
import Sidebar from './Sidebar'

export default function Navbar({user, owner, setOwner, cursor, lang, setLang}) {
    const dispatch = useDispatch()
    const history = useHistory()
    const [isOpen, toggleOpen] = useCycle(false, true)
    const containerRef = useRef(null)
    const {height} = useDimensions(containerRef)

    const handleLogout = () => {
        if (user) {
            auth.signOut().then(() => {
                dispatch(logout())
            })
        } else {
            history.push("/login")
            window.scrollTo(0, 0)
        }
        if (owner) {
            setOwner(false)
        }
    }

    const container = {
        hidden: { opacity: 0 },
        show: {
            opacity: 1,
            transition: {
                staggerChildren: 0.2,
                delayChildren: 2,
            }
        }
    }
      
    const item = {
        hidden: { opacity: 0 },
        show: { opacity: 1 }
    }

    const sidebar = {
        open: (height = 1000) => ({
            clipPath: `circle(${height * 2 + 200}px at calc(100vw - 40px) 50px)`,
            transition: {
                type: "spring",
                stiffness: 20,
                restDelta: 2
            }
        }),
        closed: {
            clipPath: "circle(0px at calc(100vw - 40px) 50px)",
            transition: {
                delay: 0.5,
                type: "spring",
                stiffness: 400,
                damping: 40
            }
        }
    }
      
    const handleToggle = () => {
        if(isOpen) {
            document.documentElement.style.overflow = 'visible'
        } else {
            document.documentElement.style.overflow = 'hidden'
        }
        toggleOpen()
    }

    const handleEnter = () => {
        cursor.current.classList.remove('outLink1')
        cursor.current.classList.add('onLink1')
    }
    const handleLeave = () => {
        cursor.current.classList.add('outLink1')
        cursor.current.classList.remove('onLink1')
        setTimeout(() => {
            cursor.current.classList.remove('outLink1')
        }, 1000);
    }

    const handleLanguage = (e) => {
        setLang(e.target.value)
        setExpD(e.target.value)
    }

    const setExpD = (lang) => {
        const d = new Date()
        const D = new Date(d.setTime(d.getTime() + (7 * 24 * 60 * 60 * 1000)))
        const expD = new Date(D).toUTCString()
        document.cookie = `${lang}; expires=${expD};`
    }    

    const toSidebar = {
        user, 
        owner,
        handleLogout,
        toggle: handleToggle,
        isOpen,
        lang,
        setLang
    }

    return (
        <Container>
            <Left>
                <Logo src={logo} alt="codmitu"/>
                <Contact>
                    <p>+40 746 960 443</p>
                    <p>codmitu@gmail.com</p>
                    <LangContainer>
                        <span>{lang === "ro" ? "Limba" : "Langu"}: </span>
                        <div>
                            <Lang value={lang} onChange={handleLanguage}>
                                <Option value="ro">RO</Option>
                                <Option value="en">EN</Option>
                            </Lang>
                            <Flag src={lang === "ro" ? ro : uk} alt="country flag"/>
                        </div>
                    </LangContainer>
                </Contact>
            </Left>

            <Right> 
                <Ul as={motion.ul} variants={container} initial="hidden" animate="show" onMouseEnter={handleEnter} onMouseLeave={handleLeave}>
                    <Li as={motion.li} variants={item} >
                        <Div>
                            <NavLink onClick={() => window.scrollTo(0, 0)} activeClassName="active" exact={true}  to="">{lang === "ro" ? "acasă" : "home"}</NavLink>
                        </Div>
                    </Li>
                    <Li as={motion.li} variants={item} >
                        <Div>
                            {owner ?
                                <NavLink onClick={() => window.scrollTo(0, 0)} activeClassName="active" to="admin">
                                    admin
                                </NavLink>
                                :
                                <NavLink onClick={() => window.scrollTo(0, 0)} activeClassName="active" to="cumpara">
                                    {lang === "ro" ? "cumpără" : "buy"}
                                </NavLink>
                            }
                        </Div>
                    </Li>
                    <Li as={motion.li} variants={item}>
                        <Div>
                            {!user ?
                                <NavLink onClick={() => window.scrollTo(0, 0)} activeClassName="active" to="login">login</NavLink>
                                :
                                <NavLink onClick={handleLogout} activeClassName="active" to="login">logout</NavLink>
                            }
                        </Div>
                    </Li>
                </Ul>

                <MyAvatar src={user?.photoUrl} alt="avatar" />
            </Right>

            <Aside 
            initial={false}
            animate={isOpen ? 'open' : 'closed'}
            custom={height}
            ref={containerRef}
            >
                <AnimatedBg as={motion.div} variants={sidebar}/>
                <Sidebar {...toSidebar}/>
                <Hamburger toggle={handleToggle}/>
            </Aside>
        </Container>
    )
}



const Container = styled.nav`
    width: 100%;
    position: relative;
    z-index: 69;
    height: 100px;
    background: linear-gradient(135deg, #3123ae8d 0%, #53a0fe8b 50%, #b3ed5088 100%);
    display: flex;
    align-items: center;
    justify-content: space-between;
    font-family: var(--fsss);
    box-shadow: 0 3px 6px rgba(0,0,0,0.16), 0 3px 6px rgba(0,0,0,0.23);
`
const Left = styled.section`
    display: flex;
    align-items: center;
    position: relative;
    z-index: 80;
    font-size: 0.8rem;
`
const Logo = styled.img`
    height: 70px;
    margin-left: 20px;
    pointer-events: none;
    @media screen and (max-width: 670px) {
        height: 50px;
    }
`
const Contact = styled.div`
    margin-left: 20px;
    >p {
        font-size: var(--xxsf);
    }
    @media screen and (max-width: 320px) {
        display: none;
    }
`
const LangContainer = styled.div`
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-top: 5px;
    >div {
        display: flex;
        align-items: center;
        gap: 5px;
    }
    @media screen and (max-width: 670px) {
        display: none;
    }
`
const Lang = styled.select`
    padding: 0 5px;
    cursor: pointer;
`
const Option = styled.option`

`
const Flag = styled.img`
    height: 20px;
`
const Right = styled.section`
    display: flex;
    align-items: center;
    margin-right: 20px;
`
const Ul = styled.ul`
    display: flex;
    align-items: center;
    padding: 0;
    @media screen and (max-width: 670px) {
        display: none;
    }
`
const Li = styled.li`
    list-style: none;
    width: 100px;
    height: 100px;
    display: grid;
    place-content: center;
`
const Div = styled.div`
    border-radius: 50%;
    padding: 2px;
    width: 30px;
    height: 30px;
    display: flex;
    align-items: center;
    justify-content: center;
    background-color: var(--cyl);
    transition: background-color 0.5s ease-in-out, border-radius 0.3s ease-in-out 0.3s, width 0.3s ease-in-out 0.3s;
    &:hover {
        background-color: var(--crl);
        width: 90px;
        border-radius: 10px;
        animation: bounce 2s both;
        @keyframes bounce { 
            0%, 30%, 50%, 80%, 100% {
                transform: translateY(0);
            } 
            20% {
                transform: translateY(-7px);
            }
            40% {
                transform: translateY(-5px);
            } 
            60% {
                transform: translateY(-2px);
            } 
        }
    }
    >a {
        color: black;
        text-decoration: none;
        height: 110%;
        line-height: 2;
        &:hover {
            color: white;
        }
        &.active {
            color: var(--crl);
            &:hover {
                color: white;
            }
        }
    }
`
const MyAvatar = styled(Avatar)`
    border: 1px solid var(--cbl);
    margin-left: 20px;
    @media screen and (max-width: 670px) {
        display: none !important;
    }
`
const Aside = styled(motion.nav)`
    @media screen and (min-width: 670px) {
        display: none;
    }
`
const AnimatedBg = styled.div`
    position: fixed; 
    top: 0;
    right: 0;
    width: 100%;
    height: 100%;
    background: linear-gradient(135deg, #8e88d4 0%, #a4cefa 50%, #d5f4a4 100%);
`